// ============================================================
// LIAM MGMT — SHARED SITE NAV + FOOTER
// ============================================================
// Single source of truth for the top navigation and footer
// across every page. To add or change a nav item or footer
// link, edit only this file.
//
// On any page, include:
//   <div id="site-nav"></div>
//   <div id="site-footer"></div>
//   <script src="site.js"></script>
// ============================================================

(function () {
  // --- Embedded logo (base64 JPEG) ---
  const LOGO = "data:image/jpeg;base64,";

  // --- NAV ITEMS ---
  // Each item: { label, href, external? }
  const NAV_ITEMS = [
    { label: "Talent",      href: "index.html#roster" },
    { label: "About",       href: "index.html#about" },
    { label: "Contact",     href: "index.html#contact" },
    { label: "Get Scouted", href: "scout.html" }
  ];

  // --- FOOTER LINKS ---
  const FOOTER_SOCIALS = [
    { label: "Instagram / @liammgmt", href: "https://instagram.com/liammgmt", external: true }
  ];

  // --- COPYRIGHT NOTICE ---
  const COPYRIGHT_NOTICE = [
    "All photographs, names, likenesses, and content on this site are the property of Liam Mgmt and the talent we represent. Unauthorized use, reproduction, or redistribution is strictly prohibited.",
    "Liam Mgmt is a registered trade name of Liam Enterprises LLC."
  ];

  // ----------------------------------------------------------
  // RENDER NAV
  // ----------------------------------------------------------
  function renderNav() {
    const mount = document.getElementById("site-nav");
    if (!mount) return;

    const navLinks = NAV_ITEMS.map(item => {
      const target = item.external ? ' target="_blank" rel="noopener"' : "";
      return `<li><a href="${item.href}"${target}>${item.label}</a></li>`;
    }).join("");

    mount.innerHTML = `
      <header class="topbar">
        <div class="topbar-inner">
          <a href="index.html" class="logo" aria-label="Liam Mgmt home">
            <img src="${LOGO}" alt="Liam Mgmt logo">
            <span class="wordmark">Liam <em>Mgmt</em></span>
          </a>
          <nav>
            <ul>${navLinks}</ul>
          </nav>
          <button class="mobile-toggle" aria-label="Open menu" aria-expanded="false">
            <span></span><span></span><span></span>
          </button>
        </div>
        <div class="mobile-menu">
          <ul>${navLinks}</ul>
        </div>
      </header>
    `;

    // Mobile menu toggle
    const toggle = mount.querySelector(".mobile-toggle");
    const menu = mount.querySelector(".mobile-menu");
    if (toggle && menu) {
      toggle.addEventListener("click", () => {
        const isOpen = menu.classList.toggle("open");
        toggle.setAttribute("aria-expanded", isOpen ? "true" : "false");
        toggle.classList.toggle("active", isOpen);
      });
      // Close on nav click
      menu.querySelectorAll("a").forEach(a => {
        a.addEventListener("click", () => {
          menu.classList.remove("open");
          toggle.classList.remove("active");
          toggle.setAttribute("aria-expanded", "false");
        });
      });
    }
  }

  // ----------------------------------------------------------
  // RENDER FOOTER
  // ----------------------------------------------------------
  function renderFooter() {
    const mount = document.getElementById("site-footer");
    if (!mount) return;

    const year = new Date().getFullYear();
    const socials = FOOTER_SOCIALS.map(item => {
      const target = item.external ? ' target="_blank" rel="noopener"' : "";
      return `<a href="${item.href}"${target}>${item.label}</a>`;
    }).join("");

    const copyrightHtml = COPYRIGHT_NOTICE.map(p => `<p>${p}</p>`).join("");

    mount.innerHTML = `
      <footer>
        <div class="footer-row">
          <div class="footer-brand">
            <img src="${LOGO}" alt="Liam Mgmt" class="footer-logo">
            <span class="footer-name">Liam Mgmt</span>
          </div>
          <div class="socials">${socials}</div>
          <div class="footer-meta">
            <span>© ${year} Liam Mgmt</span>
            <span><a href="privacy.html">Privacy</a> &nbsp;·&nbsp; liammgmt.com</span>
          </div>
        </div>
        <div class="footer-legal">
          ${copyrightHtml}
        </div>
      </footer>
    `;
  }

  // ----------------------------------------------------------
  // INITIALIZE
  // ----------------------------------------------------------
  function init() {
    renderNav();
    renderFooter();
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }
})();
